import { useState } from "react"

import useCanvasObjects from '../hooks/useCanvasObjects';
import Sidebar from './Sidebar';
import CanvasContainer from './CanvasContainer';

function Main() {
    const canvasRef = useRef(null);
    
        const [objects, setObjects] = useState([]);
        const [draggingId, setDraggingId] = useState(null);
        const [offset, setOffset] = useState({ x: 0, y: 0 });




    const canvas = useCanvasObjects();
    const [doubleClickedObj, setDoubleClickedObj] = useState('');

    return (
        <div className="main">
            <Sidebar
                newObject={canvas.newObject}
                doubleClickedObj={doubleClickedObj}
                setDoubleClickedObj={setDoubleClickedObj}
                objects={canvas.objects}
            ></Sidebar>
            <CanvasContainer
                canvas={canvas}
                setDoubleClickedObj={setDoubleClickedObj}
            ></CanvasContainer>
        </div>
    );
}

export default Main;
